// PLATFORM_CATALOG_SYNC — regenerate execute_action tool catalog
// Reads api_registry_v2 + action_map_v2, builds catalog, patches MCP Gateway workflow

const cfg = $input.first().json;
const BASE = cfg.n8nBaseUrl;
const headers = { 'X-N8N-API-KEY': cfg.apiKey };

// 1. Fetch enabled domains from api_registry_v2
const regResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${BASE}/data-tables/${cfg.registryTableId}/rows?limit=250`,
  headers
});
const domains = (regResp.data || regResp).filter(r => String(r.enabled) === 'true');

// 2. Fetch ALL actions from action_map_v2 (paginated — max 250 per call)
let allActions = [];
let offset = 0;
while (true) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE}/data-tables/${cfg.actionTableId}/rows?limit=250&offset=${offset}`,
    headers
  });
  const rows = resp.data || resp;
  allActions = allActions.concat(rows);
  if (rows.length < 250) break;
  offset += 250;
}
const enabledActions = allActions.filter(a => String(a.enabled) === 'true');

// 3. Group by category → domain → actions
const categoryMap = {};
for (const domain of domains) {
  const cat = (domain.category || 'OTHER').toUpperCase();
  if (!categoryMap[cat]) categoryMap[cat] = [];
  const acts = enabledActions
    .filter(a => a.api_name === domain.api_name)
    .map(a => a.action)
    .sort();
  if (acts.length > 0) {
    categoryMap[cat].push(`${domain.api_name}(${acts.join(',')})`);
  }
}

// 4. Generate catalog string in fixed category order
const ORDER = ['AI','CRM','PRODUCTIVITY','MARKETING','ANALYTICS','CMS','CREATIVE','DEPLOYMENT'];
let catalog = "Execute any API action through the gateway. Input: domain (string), action (string), client (string - 'kahuna' or 'ascend'), params (object - action-specific parameters).\n\nAVAILABLE DOMAINS AND ACTIONS (call directly \u2014 no need for list_domains/list_actions/get_action_schema first):\n\n";

for (const cat of ORDER) {
  if (categoryMap[cat] && categoryMap[cat].length > 0) {
    catalog += `${cat}: ${categoryMap[cat].join(' | ')}\n\n`;
    delete categoryMap[cat];
  }
}
// Append any extra categories not in ORDER
for (const cat of Object.keys(categoryMap).sort()) {
  if (categoryMap[cat].length > 0) {
    catalog += `${cat}: ${categoryMap[cat].join(' | ')}\n\n`;
  }
}
catalog += "PARAM HINTS: For 'passthrough' domains (AI, Apollo, Gong, Semrush, Vercel, etc), params go directly as the API body. For 'handler' domains (HubSpot, Google, Slack, etc), check get_action_schema if unsure about required params.";

// 5. GET current MCP Gateway workflow
const wf = await this.helpers.httpRequest({
  method: 'GET',
  url: `${BASE}/workflows/${cfg.gatewayWorkflowId}`,
  headers
});

// 6. Find execute_action node and update description
let found = false;
let oldLen = 0;
for (const node of wf.nodes) {
  if (node.parameters && node.parameters.name === 'execute_action') {
    oldLen = (node.parameters.description || '').length;
    if (oldLen === catalog.length) {
      return [{ json: { success: true, skipped: true, reason: 'catalog unchanged', catalog_length: catalog.length, timestamp: new Date().toISOString() } }];
    }
    node.parameters.description = catalog;
    found = true;
    break;
  }
}
if (!found) throw new Error('execute_action node not found in MCP Gateway workflow');

// 7. PUT updated workflow (only required fields)
await this.helpers.httpRequest({
  method: 'PUT',
  url: `${BASE}/workflows/${cfg.gatewayWorkflowId}`,
  headers: { ...headers, 'Content-Type': 'application/json' },
  body: { name: wf.name, nodes: wf.nodes, connections: wf.connections, settings: wf.settings }
});

// 8. Log change via gateway
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://mmurawala.app.n8n.cloud/webhook/orchestrate-v2',
  headers: { 'Content-Type': 'application/json', 'x-api-key': cfg.gwMasterKey },
  body: {
    domain: 'handover', action: 'log_change', client: 'ascend',
    params: {
      workflow_name: 'PLATFORM_CATALOG_SYNC',
      change_type: 'catalog_refresh',
      description: `Auto-refreshed execute_action catalog: ${domains.length} domains, ${enabledActions.length} enabled actions, ${catalog.length} chars`,
      date: new Date().toISOString()
    }
  }
});

return [{
  json: {
    success: true,
    domains_count: domains.length,
    enabled_actions_count: enabledActions.length,
    catalog_length: catalog.length,
    old_catalog_length: oldLen,
    timestamp: new Date().toISOString()
  }
}];
